const input = $input.first().json;
const topics = Array.isArray(input.topics) ? input.topics.filter((t) => typeof t === 'string' && t.trim()) : [];
const normalizedTopics = topics.map((t) => t.trim());
const maxArticlesValue = Number(input.max_articles);
const maxArticles = Number.isFinite(maxArticlesValue) && maxArticlesValue > 0 ? maxArticlesValue : 5;

return {
  json: {
    sessionId: input.sessionId || input.session_id || null,
    userId: input.user_id || null,
    email: input.email || '',
    username: input.username || '',
    newsletterQuery: normalizedTopics.length > 0 ? normalizedTopics.join(' OR ') : 'latest news',
    preferences: {
      topics: normalizedTopics,
      frequency: input.frequency || 'daily',
      send_day: input.send_day || null,
      send_day_of_month: input.send_day_of_month || null,
      send_time: input.send_time || null,
      tone: input.tone || 'neutral',
      length: input.length || 'short',
      format: input.format || 'personal_news',
      max_articles: maxArticles,
      is_subscribed: input.is_subscribed !== false
    },
    maxArticles
  }
};

