=Preferences:
{{ JSON.stringify($('Prepare newsletter request2').item.json.preferences) }}

Articles:
{{ JSON.stringify($json.articles) }}

Write a personalized newsletter using the preferences above. Return ONLY valid JSON with this schema:
{
  "subject": "",
  "body": "",
  "articles": [
    {
      "title": "",
      "summary": "",
      "url": ""
    }
  ]
}

Rules:
- Use the topics and tone from preferences.
- Respect the length preference: short or detailed.
- Keep the body ready for email delivery.
- Select at most 5 articles.
- If there are no useful articles, still write a short newsletter based on the preferences.

parameters.jsCode:
const input = $input.first().json;
const prepareData = $('Prepare newsletter request2').first().json;
const fallbackArticles = Array.isArray(input.articles) ? input.articles : [];
let parsed;
try {
  parsed = JSON.parse(input.output || '{}');
} catch (error) {
  parsed = {
    subject: 'Your 101Bot newsletter',
    body: String(input.output || ''),
    articles: fallbackArticles.slice(0, 5).map((a) => ({
      title: a.title || 'Article',
      summary: a.description || '',
      url: a.url || ''
    }))
  };
}
const articles = Array.isArray(parsed.articles) ? parsed.articles.slice(0, 5) : [];
return [{
  json: {
    subject: parsed.subject || 'Your 101Bot newsletter',
    body: parsed.body || '',
    articles,
    email: prepareData.email || '',
    username: prepareData.username || ''
  }
}];

const input = $('Normalize newsletter output1').first().json;

const articlesHtml = (Array.isArray(input.articles) ? input.articles : [])
  .map(a => `
    <div style="margin-bottom: 24px; padding: 16px; border-left: 4px solid #4F46E5; background: #f9f9f9; border-radius: 4px;">
      <h3 style="margin: 0 0 8px 0; font-size: 16px;">
        <a href="${a.url}" style="color: #4F46E5; text-decoration: none;">
          ${a.title}
        </a>
      </h3>
      <p style="margin: 0; color: #555; font-size: 14px; line-height: 1.5;">
        ${a.summary}
      </p>
      <a href="${a.url}" style="display: inline-block; margin-top: 8px; font-size: 12px; color: #888;">
        Read more →
      </a>
    </div>
  `)
  .join('');

const html = `
<!DOCTYPE html>
<html>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 24px; color: #333;">

  <div style="background: #4F46E5; padding: 24px; border-radius: 8px; margin-bottom: 32px;">
    <h1 style="color: white; margin: 0; font-size: 22px;">📰 101Bot Newsletter</h1>
    <p style="color: #c7d2fe; margin: 8px 0 0 0; font-size: 14px;">
      ${input.subject}
    </p>
  </div>

  <p style="font-size: 15px; line-height: 1.6; margin-bottom: 28px;">
    ${input.body}
  </p>

  ${articlesHtml}

  <hr style="border: none; border-top: 1px solid #eee; margin: 32px 0;">

  <p style="color: #aaa; font-size: 12px; text-align: center;">
    Sent by 101Bot for leo
  </p>

</body>
</html>
`;

return [
  {
    json: {
      subject: input.subject,
      body: input.body,
      articles: input.articles,
      html
    }
  }
];

const input = $('Normalize newsletter output1').first().json;
const fields = (Array.isArray(input.articles) ? input.articles : []).slice(0, 5).map((a) => ({
  name: (a.title || 'Article').substring(0, 256),
  value: `${a.summary || ''}${a.url ? '\n' + a.url : ''}`.trim().substring(0, 1024),
  inline: false
}));

return [{
  json: {
    embeds: [{
      title: input.subject || 'News Digest',
      description: (input.body || '').substring(0, 4096),
      color: 5814783,
      fields,
      footer: { text: `Powered by 101Bot${input.username ? ' for ' + input.username : ''}` }
    }]
  }
}];
